#include <stdio.h>
#include <stdlib.h>

struct TreeNode {
   int val;
   struct TreeNode *left;
   struct TreeNode *right;
};

int maxSumBST(struct TreeNode* root) {
   int max_sum = 0;
   dfs(root, &max_sum);
   return max_sum;
}

void dfs(struct TreeNode* node, int* max_sum) {
   if (!node) return;

   int sum = node->val;
   int min_val = node->val;
   int max_val = node->val;
   int is_bst = 1;

   if (node->left) {
      int left_sum;
      int left_min;
      int left_max;
      int left_is_bst;
      dfs(node->left, &left_sum);
      left_min = node->left->val;
      left_max = node->left->val;
      left_is_bst = 1;

      if (left_is_bst) {
         sum += left_sum;
         min_val = left_min;
         max_val = left_max;
      } else {
         is_bst = 0;
      }
   }

   if (node->right) {
      int right_sum;
      int right_min;
      int right_max;
      int right_is_bst;
      dfs(node->right, &right_sum);
      right_min = node->right->val;
      right_max = node->right->val;
      right_is_bst = 1;

      if (right_is_bst) {
         sum += right_sum;
         min_val = right_min;
         max_val = right_max;
      } else {
         is_bst = 0;
      }
   }

   if (is_bst) {
      if (sum > *max_sum) {
         *max_sum = sum;
      }
   }
}

