code.Java:
public class Solution {
   int max_sum = 0;

   public int maxSumBST(TreeNode root) {
      dfs(root);
      return max_sum;
   }

   public int[] dfs(TreeNode node) {
      if (node == null) return new int[] {0, Integer.MAX_VALUE, Integer.MIN_VALUE, 1};

      int[] left = dfs(node.left);
      int[] right = dfs(node.right);

      int sum = left[0] + right[0] + node.val;
      int min_val = Math.min(left[1], Math.min(right[1], node.val));
      int max_val = Math.max(left[2], Math.max(right[2], node.val));
      int is_bst = left[3] == 1 && right[3] == 1 && node.val > left[2] && node.val < right[1] ? 1 : 0;

      if (is_bst) {
         if (sum > max_sum) {
            max_sum = sum;
         }
      }

      return new int[] {sum, min_val, max_val, is_bst};
   }
}

